import json
import boto3
import os
import hashlib
import time
from datetime import datetime
from botocore.exceptions import ClientError

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
cloudwatch_client = boto3.client('logs')

ALLOWED_CONTENT_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'image/webp']
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB
ALLOWED_BUCKETS = os.environ.get('ALLOWED_SOURCE_BUCKETS', '').split(',')
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', '')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')

def validate_s3_event(event):
    """Validate S3 event structure and extract bucket/key"""
    if 'Records' not in event or len(event['Records']) == 0:
        raise ValueError("Invalid S3 event structure")
    
    record = event['Records'][0]
    if record.get('eventSource') != 'aws:s3':
        raise ValueError("Event source is not S3")
    
    bucket = record['s3']['bucket']['name']
    key = record['s3']['object']['key']
    
    if ALLOWED_BUCKETS and bucket not in ALLOWED_BUCKETS:
        raise ValueError(f"Bucket {bucket} not in allowed list")
    
    return bucket, key

def validate_object_metadata(bucket, key):
    """Validate object size and content type"""
    try:
        response = s3_client.head_object(Bucket=bucket, Key=key)
    except ClientError as e:
        raise ValueError(f"Cannot access object: {str(e)}")
    
    content_length = response.get('ContentLength', 0)
    if content_length > MAX_FILE_SIZE:
        raise ValueError(f"File size {content_length} exceeds maximum {MAX_FILE_SIZE}")
    
    content_type = response.get('ContentType', '')
    if content_type not in ALLOWED_CONTENT_TYPES:
        raise ValueError(f"Content type {content_type} not allowed")
    
    return response

def sanitize_key(key):
    """Sanitize S3 key to prevent path traversal"""
    key = key.replace('../', '').replace('..\\', '')
    key = key.lstrip('/')
    
    if '..' in key or key.startswith('/'):
        raise ValueError("Invalid key path detected")
    
    return key

def process_image(bucket, key):
    """Process the image - placeholder for actual image processing logic"""
    try:
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        
        file_hash = hashlib.sha256(image_data).hexdigest()
        
        metadata = {
            'original_bucket': bucket,
            'original_key': key,
            'file_hash': file_hash,
            'processed_timestamp': datetime.utcnow().isoformat(),
            'file_size': len(image_data)
        }
        
        processed_data = image_data
        
        return processed_data, metadata
        
    except ClientError as e:
        raise Exception(f"Error reading from S3: {str(e)}")

def write_to_s3(data, metadata, original_key):
    """Write processed image and metadata to output bucket"""
    if not OUTPUT_BUCKET:
        raise ValueError("OUTPUT_BUCKET environment variable not set")
    
    sanitized_key = sanitize_key(original_key)
    output_key = f"processed/{sanitized_key}"
    metadata_key = f"metadata/{sanitized_key}.json"
    
    try:
        s3_client.put_object(
            Bucket=OUTPUT_BUCKET,
            Key=output_key,
            Body=data,
            ServerSideEncryption='AES256',
            Metadata={
                'processed': 'true',
                'original-key': original_key
            }
        )
        
        s3_client.put_object(
            Bucket=OUTPUT_BUCKET,
            Key=metadata_key,
            Body=json.dumps(metadata, indent=2),
            ContentType='application/json',
            ServerSideEncryption='AES256'
        )
        
        return output_key, metadata_key
        
    except ClientError as e:
        raise Exception(f"Error writing to S3: {str(e)}")

def send_notification(message, subject):
    """Send SNS notification"""
    if not SNS_TOPIC_ARN:
        print("SNS_TOPIC_ARN not set, skipping notification")
        return
    
    try:
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, indent=2)
        )
    except ClientError as e:
        print(f"Error sending SNS notification: {str(e)}")

def lambda_handler(event, context):
    """Main Lambda handler"""
    start_time = time.time()
    
    try:
        print(f"Received event: {json.dumps(event)}")
        
        bucket, key = validate_s3_event(event)
        print(f"Processing image from bucket: {bucket}, key: {key}")
        
        sanitized_key = sanitize_key(key)
        
        validate_object_metadata(bucket, sanitized_key)
        print(f"Object validation passed for {sanitized_key}")
        
        processed_data, metadata = process_image(bucket, sanitized_key)
        print(f"Image processed successfully. Hash: {metadata['file_hash']}")
        
        output_key, metadata_key = write_to_s3(processed_data, metadata, sanitized_key)
        print(f"Results written to S3: {output_key}")
        
        processing_time = time.time() - start_time
        
        notification_message = {
            'status': 'success',
            'original_bucket': bucket,
            'original_key': sanitized_key,
            'output_bucket': OUTPUT_BUCKET,
            'output_key': output_key,
            'metadata_key': metadata_key,
            'file_hash': metadata['file_hash'],
            'processing_time_seconds': round(processing_time, 2),
            'timestamp': datetime.utcnow().isoformat()
        }
        
        send_notification(notification_message, f"Image Processing Success: {sanitized_key}")
        
        return {
            'statusCode': 200,
            'body': json.dumps(notification_message)
        }
        
    except ValueError as e:
        error_message = f"Validation error: {str(e)}"
        print(error_message)
        
        send_notification({
            'status': 'validation_error',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }, "Image Processing Validation Error")
        
        return {
            'statusCode': 400,
            'body': json.dumps({'error': error_message})
        }
        
    except Exception as e:
        error_message = f"Processing error: {str(e)}"
        print(error_message)
        
        send_notification({
            'status': 'error',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }, "Image Processing Error")
        
        return {
            'statusCode': 500,
            'body': json.dumps({'error': error_message})
        }


